using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ───────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullFormat()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExactFormat()
    {
        string result = _formatter.FormatPhoneNumber("8005559876");

        Assert.AreEqual("(800) 555-9876", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_Throws(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ───────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsName()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseDashed()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        string result = _formatter.GenerateSlug("C# is Great!!");

        StringAssert.Matches(result, new(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartOrEndWithDash()
    {
        string result = _formatter.GenerateSlug("  --Hello World--  ");

        StringAssert.DoesNotMatch(result, new(@"^-|-$"));
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsesToSingleDash()
    {
        string result = _formatter.GenerateSlug("one   two   three");

        Assert.AreEqual("one-two-three", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_EndsWithTwoDecimals()
    {
        string result = _formatter.FormatCurrency(10m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(49.95m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_MatchesDecimalPattern()
    {
        string result = _formatter.FormatCurrency(1234.50m, "$");

        StringAssert.Matches(result, new(@"^\$\d+\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        string result = _formatter.FormatCurrency(-5.00m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsExactFormat()
    {
        string result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

